class Solution {
public:
    vector<vector<string>> findDuplicate(vector<string>& paths) {
        unordered_map<string, int> fileCount;
        vector<vector<string>> result;

        for (string path : paths) {
            string pathComponents = path;
            string fileName = pathComponents.substr(pathComponents.find_last_of('/') + 1);
            string fileContent = paths[paths.size() - fileName.length() - 1];
            fileCount[fileContent]++;
        }

        for (auto it = fileCount.begin(); it != fileCount.end(); ++it) {
            if (it->second >= 2) {
                vector<string> group;
                string filePath = it->first;
                int index = filePath.find_last_of('/') + 1;
                string fileName = filePath.substr(index);
                group.push_back(fileName);
                result.push_back(group);
            }
        }

        return result;
    }
};
